def perceive(data):
    text = data if isinstance(data, str) else (data.get("text", "") if isinstance(data, dict) else str(data))
    low = text.lower()
    severity = 0
    for keyword, weight in (("critical", 10), ("malware", 9), ("ransomware", 10),
                            ("exploit", 8), ("breach", 9), ("bruteforce", 6),
                            ("portscan", 4), ("scan", 4), ("login", 2)):
        if keyword in low:
            severity = max(severity, weight)
    threat_active = severity >= 6
    return {"severity": severity, "threat_active": threat_active}
